module LoanwordRules

class LossAxis {
  name: String
  title: String
  message: String
}

class LoanwordRule {
  sourceLexeme: String
  canonicalEnglish: String
  requiresVocabularyAdmission: Boolean
  axes: Listing<LossAxis>
}

loanword = new LoanwordRule {
  sourceLexeme = "Fingerspitzengefühl"
  canonicalEnglish = "Fingerspitzengefühl"
  requiresVocabularyAdmission = false
  axes = new Listing<LossAxis> {
    new LossAxis {
      name = "lexicalization"
      title = "lexicalization"
      message = "A gloss like tact lexicalizes only one residue and drops the compound surface."
    }
    new LossAxis {
      name = "gefuhl_register"
      title = "Gefühl register"
      message = "Gefühl carries embodied social judgment that no thin English substitute preserves."
    }
    new LossAxis {
      name = "spitzen_valence"
      title = "Spitzen valence"
      message = "The sharpened leading edge remembered by Spitzen vanishes once the word is paraphrased."
    }
    new LossAxis {
      name = "lineage"
      title = "lineage"
      message = "The strategic and cultural lineage disappears when the term is flattened into etiquette."
    }
  }
}
